import { runs, tasks } from "@trigger.dev/sdk";
import fs from "fs";

async function main() {
  const trial_id = fs.readFileSync("/logs/trial_id", "utf-8").trim();
  const taskId = `human-approval-workflow-${trial_id}`;

  const handle = await tasks.trigger(taskId, { name: "Test User" });
  console.log(`Run ID: ${handle.id}`);

  // Poll for the token ID in the logs
  let tokenId: string | undefined;
  while (!tokenId) {
    const run = await runs.retrieve(handle.id);
    if (run.status === "FAILED") {
        console.error("Run failed");
        process.exit(1);
    }

    // In v4, waitpoints are part of the run details or can be fetched
    // However, the easiest way to get the tokenId as per requirements is to find it in the logs
    // or use the waitpoints API if available.
    // Let's try to list waitpoints for this run.
    const waitpoints = await runs.listWaitpoints(handle.id);
    if (waitpoints.data && waitpoints.data.length > 0) {
        tokenId = waitpoints.data[0].id;
    } else {
        await new Promise(resolve => setTimeout(resolve, 1000));
    }
  }

  console.log(`Token ID: ${tokenId}`);
}

main().catch(console.error);

